{
  "schema": "brainflow.procedure.v1",
  "name": "cli_arglen_guard",
  "intent": "Reduce Windows CLI arg-length risk by preferring file-based inputs and short command lines.",
  "rules": [
    "Prefer writing payloads to temp files and passing file paths instead of long inline JSON/args.",
    "If a command line may exceed 7000 characters, refactor to use files.",
    "When possible, use config files or stdin instead of repeated flags."
  ]
}
